import{_ as n,W as r,X as s,Y as o,Z as a,$ as e,a0 as i,a2 as h,a1 as p,C as c}from"./framework-a4c02b8f.js";const d={},l=a("p",null,"虽然去年是农历年末总结的，但是今年就以公历年来吧。",-1),_=p('<h1 id="一、spring" tabindex="-1"><a class="header-anchor" href="#一、spring" aria-hidden="true">#</a> 一、Spring</h1><p>在春天，我与时值博0的J双飞至北京。</p><p>在J在鹅厂实习的时光里，我们游览了北京的许多景点与餐馆：</p><p>我们在故宫品鉴古树等级，在国博穿越史前至明清，在圆明园护照集章，两次奥森看花开前后，在地坛逛古巷，在颐和园乘船渡湖，在八达岭攀登长城……</p><p>我们在Cheesecake Factory狂吃芝士蛋糕，与贵妃品鉴川菜与GC的蝴蝶酥，在LadyM说感觉不如CCF，在木屋烧烤无限续冰酒杯、被猪蹄辣翻，在蓝蛙鞭笞UM的shakeshack……</p><p>但是，好景不长，很快疫情便来了。</p><h1 id="二、instant-blue" tabindex="-1"><a class="header-anchor" href="#二、instant-blue" aria-hidden="true">#</a> 二、Instant Blue</h1><p>五月初，我第一次参加了某小团体线下歌会，未曾想那竟然成为了最后一次。这也使我怅然若失，陷入了一段长期的浑浑噩噩。</p>',8),u=p('<p>在家的这段短暂暑假之中，我学习了许多互联网数据挖掘相关的知识，也切实挖到了一些东西，不过这些就不在这里说了吧……</p><p>等到八月，我回到了北京，继续进行在宇宙厂的实习，这期间也是我收到的四个月验证码轰炸的开始。</p><h1 id="三、寒冬与骑行" tabindex="-1"><a class="header-anchor" href="#三、寒冬与骑行" aria-hidden="true">#</a> 三、寒冬与骑行</h1><p>今年的秋季，胜似寒冬。</p><p>见形势不对，我结束了实习，并开始投递秋招，但是今年让我见识了互联网寒冬……以至于我后来开始报名雅思考试，准备两周从零速通雅思。</p><p>国庆后，我终于忍不住了，继续进行与J的未竟之业。我一个人去了工美馆、科技馆、军博。</p><p>但是这样太孤独了。于是我买来了我的同行者——我的自行车。尔后又加入了学校的车协。</p><p>我骑行去到了不少更远的地方，最远的一次单日骑行了123km。</p><p>但是当我认为我还将骑去更多地方的时候，疫情，它又来了。</p><p>于是在被封了一个月后，预定的雅思考试也因疫情取消，我今年第三次润回了故乡。</p><h1 id="四、间章" tabindex="-1"><a class="header-anchor" href="#四、间章" aria-hidden="true">#</a> 四、间章</h1><p>于是今年到达了尾声——12月。虽然这是今年的最后一个月，但是这一个月发生的事特别多。</p><p>回程高铁同车厢现阳，我第一次体验了酒店隔离，很有可能也是最后一次。</p><p>但是在隔离中途，放开了。于是我赶忙去杭州再参加了一次雅思。</p><p>考完之后我又奔赴上海进行现场面试，并收获了两个offer，最终在码农和矿工之中选择了矿工。</p><p>随后我回到了丽水，参加了外婆的葬礼。</p><p>从葬礼回来之后，我阳了。</p><hr><p>这就是我的今年，有着很多遗憾，但也充斥着许多改变。</p><p>遗憾是令人无奈的，毕竟我也不能改变这些遗憾。我能做的只是在遗憾发生之后，通过其他改变去弥补它。</p><p>正如某位up主所言：“走在阳光下”。今年我确实在尝试，虽然疫情带来了许多阻碍，但是我确实在走。</p><p>而今已经放开，不知道明年会是怎样的一年。期望是顺利的一年。</p><p>下一站……</p>',23);function f(m,x){const t=c("RouterLink");return r(),s("div",null,[l,o(" more "),_,a("p",null,[e("书接上文，疫情来临，J走了，我也逃回了故乡，这是今年我第二次逃回故乡，第一次在"),i(t,{to:"/posts/Life/AnnualReview_2021.html"},{default:h(()=>[e("年度总结｜2021")]),_:1}),e("。")]),u])}const C=n(d,[["render",f],["__file","AnnualReview_2022.html.vue"]]);export{C as default};
